1371 void llvm::propagateIRFlags(Value *I, ArrayRef<Value *> VL, Value *OpValue,
1372                             bool IncludeWrapFlags) {
1373   auto *VecOp = dyn_cast<Instruction>(I);
1374   if (!VecOp)
