1376   auto *Intersection = (OpValue == nullptr) ? dyn_cast<Instruction>(VL[0])
1377                                             : dyn_cast<Instruction>(OpValue);
1378   if (!Intersection)
1379     return;
1380   const unsigned Opcode = Intersection->getOpcode();
